class Solution {
    public List<Integer> powerfulIntegers(int x, int y, int bound) {
        List<Integer> result = new ArrayList<>();
        for (int i = Math.max(x, y); i <= bound; i += x) {
            for (int j = Math.max(x, y); j <= bound; j += y) {
                int product = i * j;
                if (product <= bound && (x * product / i) % y == 0 && (y * product / j) % x == 0) {
                    result.add(product);
                }
            }
        }
        return result;
    }
}
```

